void process() {
    for (int i = 0; i < 100000; ++i) {
        // std::endl forces a flush of the output buffer on every iteration
        std::cout << i << std::endl;
    }
}

int main() {
    process();
    return 0;
}

output.optimized_code:
#include <iostream>

void process() {
    for (int i = 0; i < 100000; ++i) {
        // '\n' just appends a newline without flushing
        std::cout << i << '\n';
    }
    std::cout << std::flush;
}

int main() {
    process();
    return 0;
}

